// ----- myman_theme_early.js -----

(function tmMmsThemeEarlyBootstrap() {
    'use strict';

    const pathname = window.location.pathname || '';
    if (pathname.includes('login.php')) return;
    if (new URLSearchParams(window.location.search).get('tm_quickview') === '1') return;

    const root = document.documentElement;
    const LS_THEME = 'tm_mms_fouc_theme';
    const LS_MENU = 'tm_mms_fouc_menu_css';
    const LS_PAGE = 'tm_mms_fouc_page_css';

    function syncFoucThemeLocalStorage(themeId, colors) {
        try {
            if (!colors || themeId === 'default') {
                localStorage.setItem(LS_THEME, JSON.stringify({
                    themeId: 'default',
                    colors: null,
                    bg: '#ffffff',
                }));
                return;
            }
            const bg = colors['--tm-dark-color'] || colors['--tm-shop-item-bg'] || '#121212';
            localStorage.setItem(LS_THEME, JSON.stringify({ themeId, colors, bg }));
        } catch (_) { /* ignore */ }
    }

    function syncFoucMenuLocalStorage(cssText) {
        try {
            if (cssText) localStorage.setItem(LS_MENU, cssText);
            else localStorage.removeItem(LS_MENU);
        } catch (_) { /* ignore */ }
    }

    function syncFoucPageCssLocalStorage(cssText) {
        try {
            if (cssText) localStorage.setItem(LS_PAGE, cssText);
            else localStorage.removeItem(LS_PAGE);
        } catch (_) { /* ignore */ }
    }

    function clearFoucBridge() {
        try {
            document.documentElement.classList.remove('tm-mms-fouc-bridging');
            document.getElementById('tm-mms-fouc-bridge')?.remove();
        } catch (_) { /* ignore */ }
    }

    window.tmSyncFoucThemeLocalStorage = syncFoucThemeLocalStorage;
    window.tmSyncFoucMenuLocalStorage = syncFoucMenuLocalStorage;
    window.tmSyncFoucPageCssLocalStorage = syncFoucPageCssLocalStorage;
    window.tmClearFoucBridge = clearFoucBridge;

    if (typeof GM_getValue !== 'function') return;

    try {
        if (GM_getValue('tm_script_enabled', true) === false) {
            root.classList.add('tm-mms-menu-ready');
            root.classList.add('tm-mms-theme-ready');
            return;
        }
    } catch (_) { /* ignore */ }

    const THEME_KEY = 'tm_equipped_theme';
    const CACHE_KEY = 'tm_theme_colors_cache';
    const PROFILE_PREFIX = 'tm:p:';

    function readProfileScoped(key, defaultValue) {
        try {
            const profileId = GM_getValue('tm_mms_last_profile_id', '');
            if (profileId) {
                const scoped = GM_getValue(`${PROFILE_PREFIX}${profileId}:${key}`, undefined);
                if (scoped !== undefined) return scoped;
            }
            const legacy = GM_getValue(key, undefined);
            if (legacy !== undefined) return legacy;
        } catch (_) { /* ignore */ }
        return defaultValue;
    }

    function hexToRgb(hex) {
        const match = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(String(hex || ''));
        if (!match) return null;
        return {
            r: parseInt(match[1], 16),
            g: parseInt(match[2], 16),
            b: parseInt(match[3], 16),
        };
    }

    function applyColors(colors) {
        if (!colors || typeof colors !== 'object') return;
        const rootEl = document.documentElement;
        const expanded = typeof window.tmBuildDerivedThemeTokens === 'function'
            ? window.tmBuildDerivedThemeTokens(colors)
            : colors;
        for (const [variable, color] of Object.entries(expanded)) {
            rootEl.style.setProperty(variable, color);
        }
        const shopBg = expanded['--tm-shop-item-bg'] || colors['--tm-shop-item-bg'];
        const shopRgb = (() => {
            const s = String(shopBg || '').trim();
            const rgba = s.match(/^rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/i);
            if (rgba) return { r: +rgba[1], g: +rgba[2], b: +rgba[3] };
            return hexToRgb(s);
        })();
        const lightShop = shopRgb
            ? (0.299 * shopRgb.r + 0.587 * shopRgb.g + 0.114 * shopRgb.b) / 255 > 0.52
            : true;
        const shopText = expanded['--tm-shop-item-text'] || colors['--tm-shop-item-text']
            || (lightShop
                ? (expanded['--tm-text-on-light'] || colors['--tm-text-on-light'] || '#343a40')
                : (expanded['--tm-text-on-dark'] || colors['--tm-text-on-dark'] || expanded['--tm-primary-color'] || colors['--tm-primary-color'] || '#e8e8e8'));
        rootEl.style.setProperty('--tm-shop-item-text', shopText);
        const bg = expanded['--tm-dark-color'] || colors['--tm-dark-color'] || shopBg;
        if (bg && String(window.__tmEarlyThemeId || readProfileScoped(THEME_KEY, 'default')) !== 'default') {
            rootEl.style.backgroundColor = bg;
        }
    }

    const themeId = String(readProfileScoped(THEME_KEY, 'default') || 'default');

    let cache = null;
    try {
        const raw = readProfileScoped(CACHE_KEY, null);
        if (raw) {
            cache = typeof raw === 'string' ? JSON.parse(raw) : raw;
        }
    } catch (_) { /* ignore */ }

    if (themeId !== 'default' && cache && cache.colors) {
        applyColors(cache.colors);
        syncFoucThemeLocalStorage(themeId, cache.colors);
    } else {
        syncFoucThemeLocalStorage(themeId, null);
    }

    window.__tmEarlyThemeId = themeId;

    // Stay blank until myman_themes.js applies the real theme (tmRevealThemeReady).

    const HIDDEN_MENU_KEY = 'tm_hidden_menu_items';
    const menuFeatureEnabled = readProfileScoped('hiddenMenuItemsEnabled', true) !== false;
    let hiddenMenuItems = [];

    try {
        const rawHidden = readProfileScoped(HIDDEN_MENU_KEY, '[]');
        hiddenMenuItems = typeof rawHidden === 'string' ? JSON.parse(rawHidden) : (rawHidden || []);
        if (!Array.isArray(hiddenMenuItems)) hiddenMenuItems = [];
    } catch (_) {
        hiddenMenuItems = [];
    }

    window.__tmMenuGuardActive = menuFeatureEnabled && hiddenMenuItems.length > 0;

    function cssAttrSubstring(value) {
        return String(value).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    }

    function buildMenuHideCss(items) {
        const rules = [
            'html:not(.tm-mms-menu-ready) .rnr-left { visibility: hidden !important; opacity: 0 !important; }',
            'html.tm-mms-menu-ready .rnr-left { visibility: visible !important; opacity: 1 !important; transition: opacity 0.12s ease-in; }',
        ];

        items.forEach((item) => {
            const href = typeof item === 'object' ? item.href : '';
            const id = typeof item === 'string' ? item : item?.id;
            if (href && href.includes('?')) {
                const escaped = cssAttrSubstring(href);
                rules.push(`.rnr-b-vmenu.simple.main li:has(> div > div > a[href*="${escaped}"]) { display: none !important; }`);
                rules.push(`.rnr-b-vmenu.simple.main li:has(> div a[href*="${escaped}"]) { display: none !important; }`);
            } else if (href) {
                const escaped = cssAttrSubstring(href);
                rules.push(`.rnr-b-vmenu.simple.main li:has(> div > div > a[href="${escaped}"]) { display: none !important; }`);
                rules.push(`.rnr-b-vmenu.simple.main li:has(> div a[href="${escaped}"]) { display: none !important; }`);
            } else if (id) {
                rules.push(`.rnr-b-vmenu.simple.main li[data-menu-id="${cssAttrSubstring(id)}"] { display: none !important; }`);
            }
        });

        return rules.join('\n');
    }

    function injectMenuGuardCss(cssText) {
        let style = document.getElementById('tm-mms-menu-early-guard');
        if (!style) {
            style = document.createElement('style');
            style.id = 'tm-mms-menu-early-guard';
            (document.head || root).appendChild(style);
        }
        style.textContent = cssText;
        syncFoucMenuLocalStorage(cssText || '');
    }

    window.tmRefreshMenuEarlyCss = function tmRefreshMenuEarlyCss(items) {
        const list = Array.isArray(items) ? items : [];
        window.__tmMenuGuardActive = menuFeatureEnabled && list.length > 0;
        if (menuFeatureEnabled && list.length > 0) {
            injectMenuGuardCss(buildMenuHideCss(list));
        } else {
            injectMenuGuardCss('');
            document.documentElement.classList.add('tm-mms-menu-ready');
        }
    };

    if (window.__tmMenuGuardActive) {
        injectMenuGuardCss(buildMenuHideCss(hiddenMenuItems));
    } else {
        syncFoucMenuLocalStorage('');
        root.classList.add('tm-mms-menu-ready');
    }
})();

/** Clears menu guard when ready. */
window.tmRevealThemedPageIfReady = function tmRevealThemedPageIfReady() {
    if (window.__tmMenuGuardActive && !document.documentElement.classList.contains('tm-mms-menu-ready')) {
        return;
    }
    document.documentElement.classList.add('tm-mms-menu-ready');
    if (typeof window.tmRevealThemeReady === 'function') {
        window.tmRevealThemeReady();
    } else {
        document.documentElement.classList.add('tm-mms-theme-ready');
    }
};


// ----- myman_performance_styles.js -----
/** Global GPU/compositor savings — injected after theme styles. */
const PERFORMANCE_STYLES_BASE = `
/* ===== Theme performance (GPU) ===== */

/* Full-screen infinite animations repaint every frame */
body::before,
body::after {
    animation: none !important;
}
body {
    background-attachment: scroll !important;
    animation: none !important;
}

/* Heading flicker / glow on every page */
h1, h2, h3, h4, h5, h6, .pagetitle {
    animation: none !important;
    text-shadow: none !important;
}

/* backdrop-filter is the #1 GPU cost — use solid panels instead (not default-theme footer) */
.rnr-top, #head-outter, #footer-outter, #footer-outterwrap,
.rnr-cw-hmenu, .rnr-cw-pagination, .rnr-cw-pagination_bottom,
.rnr-s-menu, .rnr-s-grid, .rnr-c-hmenu, .rnr-c-pagination, .rnr-c-pagination_bottom,
.jconfirm, #tm-memory-game-overlay, #tm-game-overlay,
.tm-modal-overlay,
#tm-mascot-interaction-panel,
#tm-notification-backdrop {
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
}

/* Drop expensive glow text on scroll/hover */
.rnr-gridtable tr.rnr-row:hover,
.rnr-row.style1:hover,
a:hover, .rnr-orderlink:hover,
.etdbadge,
.jconfirm-box .title,
.jconfirm-box .closeIcon:hover,
#footer-outterwrap td, #footer-outterwrap span,
.rnr-s-grid b, .rnr-s-grid strong,
.tm-settings-section h3,
#tm-positive-message, #tm-achievement-notification {
    text-shadow: none !important;
}

/* Modal overlays: solid dim, no blur — never reuse panel/shop card bg (that flattens the shop) */
.jconfirm { background: rgba(0, 0, 0, 0.82) !important; }
.tm-modal-overlay { background: rgba(0, 0, 0, 0.62) !important; }

/* Level-up screen (rare) — skip heavy blur */
#tm-level-up-overlay,
.tm-level-up-content {
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
}
.tm-level-up-content {
    background: var(--tm-modal-bg, rgba(14, 14, 20, 0.96)) !important;
}
.tm-level-up-content::after {
    animation: none !important;
}

/* Default-theme decorative modal loops */
.tm-modal-content[style*="linear-gradient"] {
    animation: none !important;
}
.tm-modal-content[style*="linear-gradient"]::before {
    display: none !important;
    animation: none !important;
}

@media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
        animation: none !important;
        transition: none !important;
    }
}
`;

const PERFORMANCE_STYLES_DEFAULT_FOOTER = `
/* Default theme: glass footer widgets (never solid shop-item-bg) */
#tm-notification-bell-btn,
#tm-refresh-timer-container,
#tm-weather-widget,
#tm-settings-btn,
#tm-daily-dashboard-widget,
#tm-xp-bar-container,
#tm-coin-balance,
.tm-footer-widget,
.tm-buff-timer,
#tm-recent-repairs-btn {
    background: var(--tm-glass-bg, linear-gradient(145deg, rgba(255,255,255,0.2) 0%, rgba(255,255,255,0.05) 100%)) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    border-color: var(--tm-glass-border, rgba(255,255,255,0.2)) !important;
}
#tm-eod-btn {
    background: var(--tm-glass-bg, linear-gradient(145deg, rgba(255,255,255,0.2) 0%, rgba(255,255,255,0.05) 100%)) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    border-color: var(--tm-glass-border, rgba(255,255,255,0.2)) !important;
}
`;

const PERFORMANCE_STYLES_NON_DEFAULT_FOOTER = `
/* Non-default themes: solid footer widgets (no glass blur) */
#tm-notification-bell-btn,
#tm-refresh-timer-container,
#tm-weather-widget,
#tm-settings-btn,
#tm-daily-dashboard-widget,
#tm-xp-bar-container,
#tm-coin-balance,
.tm-footer-widget,
.tm-buff-timer,
#tm-recent-repairs-btn {
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    background: var(--tm-shop-item-bg) !important;
    border-color: var(--tm-shop-item-border, rgba(255,255,255,0.2)) !important;
}
#tm-eod-btn {
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    background: var(--tm-shop-item-bg) !important;
    border-color: var(--tm-shop-item-border, rgba(255,255,255,0.2)) !important;
}

/* Cheaper transitions (avoid compositing "all") */
.rnr-button, .btn, .tm-footer-widget, #tm-xp-bar-container,
#tm-settings-btn, #tm-refresh-timer-container, #tm-recent-repairs-btn, #tm-eod-btn {
    transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease, opacity 0.15s ease !important;
}
`;

function tmInjectPerformanceStyles() {
    const themeId = typeof window.tmReadEquippedThemeId === 'function'
        ? window.tmReadEquippedThemeId()
        : String(window.__tmEarlyThemeId || 'default');
    const isDefaultTheme = themeId === 'default';

    document.getElementById('tm-performance-styles')?.remove();
    const el = document.createElement('style');
    el.id = 'tm-performance-styles';
    if (isDefaultTheme) {
        return;
    }
    el.textContent = PERFORMANCE_STYLES_BASE + PERFORMANCE_STYLES_NON_DEFAULT_FOOTER;
    document.head.appendChild(el);
}

window.tmInjectPerformanceStyles = tmInjectPerformanceStyles;


